    ['Beyond the Sun'] = {
        id = 76,
        start_npc = 'Maat',
        start_zone = 'Ru\'Lude Gardens',
        start_pos = 'H-5',
        description = 'After clearing all of Maat\'s final challenges, you will finally learn his secret...',
