    ['Full Speed Ahead!'] = {
        id = 179,
        start_npc = 'Mapitoto',
        start_zone = 'Upper Jeuno',
        start_pos = 'G-7',
        description = 'Hop on board Mapitoto\'s slightly ornery raptor and head to Batallia Downs. Seek out Syrillia once you have arrived.',
        reward = 'Raptor companion\nTrainer\'s whistle',
        fame = 'Jeuno',
        fame_level = '1',
        title = 'Raptor Wrangler',
        repeatable = nil,
        previous = {'Chocobo\'s Wounds'},
        next = {'The Flying Machine of Eld'},
        requirements = nil,
        walkthrough = '1. Speak to Mapitoto on any job level 20 or higher.\n   - You must also have the Map of the Jeuno area to proceed.\n   - Rusese of M&P Market nearby will sell you the map for 600 gil.\n2. Accept the offer to feed her Raptor as it is trying to bite off her nose like it\'s a little-wittle sausage.\n3. She will mark several locations on your map to go.\n   - These are viewable on the map under the green NPC marker section.\n     - Map -> Markers -> (press right or left in the menu)\n4. Travel to the points on the map. There is very visable a pillar of light on the ground to show when you are getting close.\n   - Be aware that the food is inside the burrows. Go around the mound until you see a rectangular entryway.\n   - You will need to get 5 of these foods.\n5. The raptor will get agitated and slower as you take longer to get to the food.\n   - This is indicated by the motivation bar slowly depleting.\n   - Note: Going up-hill drastically reduces the Raptor\'s motivation.\n   - When the pep bar has reached 50% or more you may /cheer to give the raptor a second wind and refill part of its motivation bar.\n6. Successfully feeding the raptor will result in a message notifying you that it has "overcome the munchies".\n   - If you take too long it will "Run off into the sunset..." presumably to meet other raptors and do raptor things.\n     - You will be prompted with the option to retry the course if this occurs.\n     - You may select to retry the course on a lower difficulty, this will keep the raptor\'s spirits up longer and fill its pep gauge faster.\n7. Once you have successfully fed the raptor rendezvous with Syrillia at (E-6) who will warp you back. Stay mounted when talking to Syrillia.\n8. A comfortable example route: J-8 → /cheer → I-7 → H-6 → /cheer → G-6 → F-7 → /cheer → E-6\n9. Return to Mapitoto in Upper Jeuno for your reward.\n   - Note that you directly receive the key item Raptor companion instead of the item Raptor Mount.',
        notes = nil,
    },
    ['Further Founts'] = {
        id = 173,
        start_npc = 'Anastase',
        start_zone = 'Ru\'Lude Gardens',
        start_pos = 'G-9',
        description = 'More geomagnetic founts have been discovered throughout the Middle Lands. Record any relevant data and report back to Anastase.',
        reward = 'New Proto-Waypoint Teleportation Destinations\n12 Trail Cookies\n3000 Conquest points\nExperience points awarded for each Geomagnetic Fount discovered',
        fame = 'Jeuno',
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'Middle Lands Investigation'},
        next = {'Beam Me Up...No, Not There!'},
        requirements = nil,
        walkthrough = 'You must zone after completing Middle Lands Investigation before you are able to accept this quest.\nSpeak to Anastase and select the first option, "Must have more warp destinations!"\nAt this point, you must discover ten more Geomagnetic Founts hidden throughout Vana\'diel by using the hints provided upon asking Anastase about his predictions:\n1. Unity Warp (125) puts you closest to this one.\n2. While in Oldton Movalpolos travel to E-13, talk to Twinkbrix, trade 2,716 gil for teleport to Mineshaft 2716, exit out of Mineshaft 2716 into Newton Movalpolos and travel to the furnace at K-8.\n3. You will be heading south from here, if the fence/gate is restricting you from going south, you will need a Firesand (drops from Moblin Roadman/Engineer). Trade the Firesand to the furnace to move the fence/gate.\n4. Drop off at I/J-9 and continue running south. You will now be heading to E-9 (4 on the Map) and exit back into Oldton Movalpolos. The geomagnetic fount is on the left near the opening of the tunnel.\n5. If you already have the HP for this zone, then you only need 1 Giant Scale and the Fount is much closer than the entrance. If you don\'t have the HP, get it at the same time at E-8.\n6. If you don\'t have the HP, get it at the same time at E-8.\nAfter attuning the Prototype attuner to each of the 10 geomagnetic founts above, return to Anastase to complete the quest.\nNote: if you have the quest Granddaddy Dearest open at the same time, Anastase will not complete this quest before you complete Granddaddy Dearest.',
        notes = nil,
    },
    ['Girl in the Looking Glass'] = {
        id = 78,
        start_npc = 'Luto Mewrilah',
        start_zone = 'Upper Jeuno',
        start_pos = 'G-8',
        description = 'Laurana\'s daughter has gone missing. She is a young girl with blonde hair, and was wearing a brown dress and a brown cap.',
        reward = nil,
        fame = nil,
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'Unlisted Qualities'},
        next = {'Mirror, Mirror'},
        requirements = nil,
        walkthrough = '1. Note: You must zone after finishing Unlisted Qualities before you can start this quest.\n2. Speak to Luto Mewrilah for a cutscene.\n3. Speak to Bheem at (F-5) for a second cutscene.\n4. Enter The Eldieme Necropolis from the entrance at Batallia Downs (G-8). This will start you at (F-9) on Map 2 of the Necropolis.\n5. Follow the hallway until you find a ??? spot at (F-9).\n6. Examine the ??? to receive a cutscene.\n7. When the cutscene ends the NM skeleton Namorodo spawns, along with your Adventuring Fellow.\n   - This confrontation is soloable at level 30 (the original level requirement for this quest).\n   - Trust Magic can be used as long as you summon trusts before checking the ???\n   - Adventuring Fellows count toward the party size limit. If there is no room in your party for your Fellow, all your trusts will despawn.\n8. Once the NM is defeated, speak to your Adventuring Fellow.\n   - Note: If you do not speak to your Adventuring Fellow before he/she despawns, you must rezone and fight the NM again.\n9. Return to Upper Jeuno for a cutscene upon speaking with Luto to complete the quest.',
        notes = nil,
    },
