    ['Mirror Images'] = {
        id = 83,
        start_npc = 'Luto Mewrilah',
        start_zone = 'Upper Jeuno',
        start_pos = 'G-8',
        description = 'Save Palometa from her mysterious captor.',
        reward = 'Increases Familiarity Limit to 120, unlocks Blessed Radiance skill.',
        fame = nil,
        fame_level = nil,
        title = nil,
        repeatable = nil,
        previous = {'Blessed Radiance'},
        next = nil,
        requirements = nil,
        walkthrough = '1. Speak to Luto for a cutscene.\n2. Head to Fei\'Yin and enter Qu\'Bia Arena at (K-8).  Home Point #1 is the closest.\nThis is a Lv.50 capped fight against a single Dark Knight demon, Vassago.  He has a very long melee delay, about 3,500 HP, and uses a unique move Blighted Gloom.\n3. Recommend setting your fellow to Stalwart Shield, as it can tank and cure itself.\n4. Blighted Gloom will always be preceded by a dialogue from your fellow: "Here it comes! Get back!."  Turn and allow your fellow to get hate back.\n   - Alternately, you can outrun it if you are have hate.\n   - If your fellow is the target of Blighted Gloom, they will take 0 damage, and counter Vassago with Blessed Radiance for ~200 damage.  Players will take moderate damage from Blighted Gloom.\n5. Fight is fairly straightforward as long as your fellow is holding hate.  You can keep them alive and let them do all the damage.\nOnce you defeat the demon, you will receive a cutscene.\n6. Return to Luto for a cutscene.\n7. Examine the door in Neptune\'s Spire for a long cutscene to complete the quest.',
        notes = nil,
    },
    ['Mirror, Mirror'] = {
        id = 79,
        start_npc = 'Luto Mewrilah',
        start_zone = 'Upper Jeuno',
        start_pos = 'G-8',
        description = 'Luto has recently discovered that another mirror bearing strange properties exists in the world. It is supposedly somewhere in San d\'Oria and she wants you to go look for it.',
