    ['Now Recording...'] = {
        id = 175,
        start_npc = 'Darcia',
        start_zone = 'Lower Jeuno',
        start_pos = 'H-7',
        description = 'Not all tests are tests of steel. In order to get permission to visit Adoulin, you must record data located in a certain part of the Middle Lands. The Adventurer\'s Mutual Aid Network will provide your reward.',
        reward = 'Experience Points (varies)\n300 Gil',
        fame = 'Jeuno',
        fame_level = nil,
        title = nil,
        repeatable = 'Yes',
        previous = {'The Geomagnetron'},
        next = nil,
        requirements = nil,
        walkthrough = '1. After completing The Geomagnetron, return to Darcia and ask if she has more work for you.\n2. Darcia will grant you a Temporary geomagnetron and ask you to return to one of the Geomagnetic Founts.\n3. Travel to one of the locations and attune the device to the Geomagnetic Fount found there. The experience points reward received will depend on the chosen fount:\n   - Ranguemont Pass: Southeastern corner, (J-10) - 200 EXP\n   - Yughott Grotto: (J-7), in the pond - 200 EXP\n   - King Ranperre\'s Tomb: (K-6), nearest to Jugner Forest Proto-Waypoint - 300 EXP\n   - Monastic Cavern: First Map, (H-10)\n   - The Eldieme Necropolis: Second map (J-10). Fall from first floor (F-8) - 400 EXP\n   - Ordelle\'s Caves: Hidden Apparatus Area (F-12)\n   - Gusgen Mines: Last map, NW corner (G-7)\n   - Dangruf Wadi: (E-11), after falling in the hole in the hidden tunnel\n   - Korroloka Tunnel: Fifth map (G-9)\n   - Palborough Mines: Second map (J-8)\n   - Gustav Tunnel: First map, at the pond closest to the Cape Teriggan exit (G-10) - 500 EXP\n   - Labyrinth of Onzozo: (J-5), Off the map in the northeast (access from the south).\n   - Maze of Shakhrami: First map (K-9) - 300 EXP\n   - Garlaige Citadel: (G-8)\n   - Crawlers\' Nest: First map (F-7) - 400 EXP\n   - Outer Horutoto Ruins: (G-7)\n   - Inner Horutoto Ruins: Second map (G-7)\n   - Toraimarai Canal: (I-6) towards Inner Horutoto Ruins\n4. Return to Darcia to complete the quest.',
        notes = nil,
    },
    ['Painful Memory'] = {
        id = 63,
        start_npc = 'Mertaire',
        start_zone = 'Lower Jeuno',
        start_pos = 'H-8',
        description = 'Take Mertaire\'s bracelet to Ranguemont Pass and immerse it in the Waters of Oblivion.',
        reward = 'Paper Knife',
        fame = 'Jeuno',
        fame_level = nil,
        title = nil,
