    ['Yet Another Trial in Tandem'] = {
        id = 162,
        start_npc = 'Luto Mewrilah',
        start_zone = 'Upper Jeuno',
        start_pos = 'G-8',
        description = 'Your comrade\'s zeal for self- improvement knows no limits, and the Magian Mooglehood stands ever ready to assist in this endeavor. Make your way to Ru\'Lude Gardens, where a new challenge awaits!',
        reward = 'Raises Adventuring Fellow level cap to 85',
