    ['Your Crystal Ball'] = {
        id = 9,
        start_npc = 'Kurou-Morou',
        start_zone = 'Lower Jeuno',
        start_pos = 'I-7',
        description = 'Create your own crystal ball to have your fortune told.',
        reward = 'Kurou-Morou will tell your fortune.',
        fame = 'Jeuno',
        fame_level = '2',
        title = 'Fortune-teller In Training',
        repeatable = nil,
        previous = nil,
        next = {'Never to Return'},
        requirements = {
            {name = 'Ahriman Lens', count = 1},
        },
        walkthrough = '1. Kurou-Morou is the fortune teller in Lower Jeuno above the Auction House. He asks you to bring him a Crystal Ball.\n2. To create a Crystal Ball, you need an Ahriman Lens.\n   - The Ahriman Lens is an Ex item, so you can\'t find it on the AH.\n   - You\'ll need to defeat Evil Eye type mobs to get one to drop.\n     - The Eyes spawn in areas such as Ranguemont Pass, Beaucedine Glacier, and Xarcabard.\n3. With the Lens in your possession, head to the Maze of Shakhrami.\n4. Go to (G-5) on the first map, which is east of the exit to Attohwa Chasm.\n   - The fastest way here is the Voidwatch Warp to Tavnazia -> Attohwa Chasm using the teleport service from any Atmacite Refiner, then go south to zone into Maze of Shakhrami.\n     - Can be unlocked by 75+ players with access to Tavnazian Safehold by talking to Owain to get a Hyacinth stratum abyssite; no Voidwatch battles or progression is necessary\n     - The 1000 requisite cruor can be attained via a Copper Voucher, killing fodder in Abyssea, or earned previously via Voidwatch.\n5. At the top of the path, you\'ll find a Rockwell.\n6. Trade your  Ahriman Lens to the Rockwell, and you\'ll get the message "You submerged the Ahriman Lens into the pool of water."\n7. You must now zone to continue the quest. After that point, you\'ll be able to check the Rockwell to obtain your Divination Sphere.\n8. Head back to Kurou-Morou and trade him your Divination Sphere. This finishes the quest, and as a reward, he will now tell your fortune when you request it.',
        notes = nil,
    },
}
